module.render:
    const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    const title = esc((args.title || '').trim());
    const body = (content || '').trim();
    return `

<div class="mdp-mod-terminal"><div class="mdp-tm-bar"><span class="mdp-tm-dot"></span><span class="mdp-tm-dot"></span><span class="mdp-tm-dot"></span><span class="mdp-tm-title">${title}</span></div><div class="mdp-tm-body">

${body}

</div></div>

`;
